function money(value) {
  const n = Number(value || 0);
  return n > 0 ? `$${n.toFixed(2)}` : 'pendiente de confirmar';
}
function digitsOnly(value) {
  const raw = String(value || '').replace(/\D/g, '');
  if (!raw) return '';
  if (raw.length === 10) return `1${raw}`;
  if (raw.length === 11 && raw.startsWith('1')) return raw;
  return raw;
}
function cadence(attempts, daysOpen) {
  const n = Number(attempts || 0) + 1;
  if (n <= 1) return { step: 'dia_1', label: 'Aviso formal amable' };
  if (n === 2) return { step: 'dia_2', label: 'Recordatorio corto' };
  if (n === 3) return { step: 'dia_3', label: 'Revision interna de cuenta' };
  if (n === 4 || Number(daysOpen || 0) >= 5) return { step: 'dia_4', label: 'Ultimo intento automatico' };
  return { step: 'dia_8_plus', label: 'Seguimiento cada 3 dias' };
}
function buildMessage(target, channel, cadenceInfo) {
  const nombre = target.nombre || 'Cliente';
  const cuenta = target.cuenta_hycite || 'S/N';
  const monto = money(target.monto_cargo_vuelta);
  const fecha = target.fecha_cargo_vuelta || 'No registrada';
  const stop = channel === 'whatsapp' ? '\n\nResponda ALTO para no recibir mensajes por este medio.' : '\n\nSi prefiere no recibir mensajes por este medio, responda ALTO.';
  const variants = {
    dia_1: `Estimado/a ${nombre},\n\nLe contactamos del equipo de resolucion de Connection Worldwide Group sobre su cuenta Royal Prestige / Hy-Cite #${cuenta}.\n\nBalance pendiente de regularizar: ${monto}\nFecha de referencia: ${fecha}\n\nQueremos revisar opciones de pago y ayudarle a llegar a un acuerdo comodo antes de que el proceso avance internamente. Puede responder a este mensaje o contactar a Patricia Caicedo al (786) 291-3042.${stop}`,
    dia_2: `Hola ${nombre}, le damos seguimiento a su cuenta Royal Prestige / Hy-Cite #${cuenta}.\n\nTenemos opciones de pago disponibles para regularizar el balance de ${monto}. Responda a este mensaje y coordinamos un acuerdo comodo.${stop}`,
    dia_3: `Estimado/a ${nombre}, su cuenta #${cuenta} continua en revision interna por balance pendiente de ${monto}.\n\nNuestro equipo de resolucion quiere hablar con usted para documentar una alternativa de pago antes de escalar el seguimiento operativo.${stop}`,
    dia_4: `Hola ${nombre}, este es nuestro ultimo intento automatico de seguimiento sobre la cuenta #${cuenta}.\n\nQueremos darle oportunidad de establecer un acuerdo de pago comodo por el balance pendiente de ${monto}. Comuniquese con Patricia Caicedo al (786) 291-3042 o responda este mensaje.${stop}`,
    dia_8_plus: `Hola ${nombre}, seguimos disponibles para ayudarle a regularizar la cuenta Royal Prestige / Hy-Cite #${cuenta}.\n\nBalance pendiente: ${monto}. Responda este mensaje para revisar opciones de pago.${stop}`
  };
  return variants[cadenceInfo.step] || variants.dia_8_plus;
}
const out = [];
for (const item of $input.all()) {
  const t = item.json;
  const cadenceInfo = cadence(t.auto_attempt_count, t.days_since_case_opened);
  const metaText = `campaign_key=cargo_vuelta_dfp_auto; case_id=${t.case_id}; cadence_step=${cadenceInfo.step}`;
  const ownerId = $env.COBRANZA_OWNER_ID || t.owner_id;
  const orgId = t.org_id || $env.FLOWSUITE_ORG_ID;
  const scheduledFor = new Date(Date.now() - 1000).toISOString();
  const emailMessage = buildMessage(t, 'email', cadenceInfo);
  const whatsappMessage = buildMessage(t, 'whatsapp', cadenceInfo);
  const phone = digitsOnly(t.telefono || t.telefono_casa);
  out.push({ json: { ...t, cadence: cadenceInfo, provider: String($env.WHATSAPP_PROVIDER || '').toLowerCase(), normalized_phone: phone, emailOutbox: t.email ? { owner_id: ownerId, org_id: orgId, contact_tipo: 'cliente', contact_id: t.cliente_id, contexto_tipo: 'cobranza', canal: 'email', destinatario: t.email, asunto: `Revision de cuenta Royal Prestige #${t.cuenta_hycite || 'S/N'}`, mensaje: emailMessage, mensaje_resuelto: emailMessage, cc_emails: $env.COBRANZA_CC_EMAIL ? [$env.COBRANZA_CC_EMAIL] : null, from_name: 'Equipo de Resolucion CWG', dispatch_provider: 'n8n', status: 'programado', scheduled_for: scheduledFor } : null, whatsappOutbox: phone ? { owner_id: ownerId, org_id: orgId, contact_tipo: 'cliente', contact_id: t.cliente_id, contexto_tipo: 'cobranza', canal: 'whatsapp', destinatario: phone, mensaje: whatsappMessage, mensaje_resuelto: whatsappMessage, dispatch_provider: 'n8n', status: 'programado', scheduled_for: scheduledFor } : null, gestion: { org_id: orgId, cliente_id: t.cliente_id, case_id: t.case_id, tipo_gestion: 'seguimiento', resultado: 'recordatorio_automatico_cargo_vuelta', notas: `Recordatorio automatico de cargo de vuelta enviado. ${cadenceInfo.label}. ${metaText}` } } });
}
return out;

